// // This module implements a simple logic gate that outputs 1 if A1 is high or A2 is low and B1 is not equal to B2, otherwise it outputs 0.
module logic_gate(
    input A1,
    input A2,
    input [1:0] B1,
    input [1:0] B2,
    input C1,
    output Y
);

    assign Y = (A1) ? 1'b1 : ((A2) ? 1'b0 : ((B1 > B2) ? 1'b1 : ((B1 < B2) ? 1'b0 : ((C1) ? 1'b1 : 1'b0))));

endmodule
